import java.nio.ByteBuffer;
import java.util.Scanner;

public class SecureBufferExample {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter a string: ");
        String input = scanner.nextLine();

        // Secure code - using ByteBuffer to handle memory allocation and copying
        byte[] buffer = new byte[10];

        ByteBuffer byteBuffer = ByteBuffer.wrap(buffer);

        if (input.length() <= buffer.length) {
            byteBuffer.put(input.getBytes());
            System.out.println("Input copied successfully!");
        } else {
            System.out.println("Input exceeds buffer size, copy operation aborted.");
        }
    }
}

